<script setup lang="ts">
const supabase=useSupabaseClient<any>(),state=ref<any>(null),message=ref('')
const federation=reactive({counterparty_did:'did:web:trusted-partner.example',trust_domains:'causal_evidence,capability_attestations'}),delegation=reactive({delegate_subject:'role:operator',scopes:'read,simulation:run',purpose:'Bounded portfolio analysis',minutes:60}),market=reactive({capability:'proof-carrying routing',provider_subject:'internal:capability-team',metric:'verified_success',target:.95,window_days:30,maximum_usd:100}),inclusion=ref('Add a dense visual dashboard with animated charts while keeping all established destinations stable.'),proposition=ref('Release a reversible capability improvement after evidence review, accessibility mitigation, and rollback validation.')
async function authed<T>(url:string,options:any={}){const{data:{session}}=await supabase.auth.getSession();return $fetch<T>(url,{...options,headers:{...(session?.access_token?{authorization:`Bearer ${session.access_token}`}:{})}})}
async function load(){state.value=await authed('/api/constitution/context')}
async function act(action:string,values:any={}){message.value='';try{await authed('/api/constitution/action',{method:'POST',body:{action,values}});message.value=`${action.replaceAll('_',' ')} completed with a proof envelope.`;await load()}catch(e:any){message.value=e?.data?.message||e?.message||'Assurance action failed.'}}
function trust(){return act('federation_trust',{...federation,trust_domains:federation.trust_domains.split(',').map(x=>x.trim()).filter(Boolean)})}function exchange(){const id=state.value?.assurance?.trusts?.[0]?.id;if(id)return act('federated_exchange',{trust_id:id})}function delegate(){return act('delegate_authority',{...delegation,scopes:delegation.scopes.split(',').map(x=>x.trim()).filter(Boolean)})}
onMounted(load)
</script>
<template><section id="federation-assurance" class="mt-5 rounded-xl border border-sky-200 bg-white p-4" aria-labelledby="assurance-heading"><div><div class="text-[10px] font-semibold uppercase tracking-[.14em] text-sky-700">Federation & assurance</div><h2 id="assurance-heading" class="mt-1 text-sm font-semibold">Sovereign exchange, causal learning, verifiable execution, and adversarial review</h2><p class="mt-1 text-xs text-gray-500">Share less, prove more, attenuate delegated authority, and fund only independently verified outcomes.</p></div><div v-if="!state" class="mt-4 text-xs text-gray-400">Loading federation assurance…</div><div v-else class="mt-4 grid gap-3 lg:grid-cols-2"><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Sovereign organizational federation</h3><div class="mt-2 grid gap-2"><input v-model="federation.counterparty_did" class="rounded border p-2 text-xs" aria-label="Counterparty decentralized identifier"><input v-model="federation.trust_domains" class="rounded border p-2 text-xs" aria-label="Trust domains"></div><div class="mt-2 flex gap-2"><button class="rounded bg-sky-700 px-3 py-2 text-xs text-white" @click="trust">Propose sovereign trust</button><button :disabled="!state.assurance.trusts.length" class="rounded border px-3 py-2 text-xs disabled:opacity-40" @click="exchange">Prepare selective evidence exchange</button></div><p class="mt-2 text-[10px] text-gray-500">{{state.assurance.trusts.length}} trusts · {{state.assurance.exchanges.length}} prepared exchanges; every delivery still requires approval.</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Continuously causal digital twin</h3><p class="mt-1 text-[10px] text-gray-500">Fuse world snapshots, causal evidence, and realized route outcomes while keeping correlations explicitly distinct from causal claims.</p><button class="mt-3 rounded bg-gray-900 px-3 py-2 text-xs text-white" @click="act('causal_twin_update')">Update causal twin</button><p v-if="state.assurance.twins[0]" class="mt-2 text-[10px] text-emerald-700">Latest: {{state.assurance.twins[0].evidence_ids.length}} evidence records · {{state.assurance.twins[0].recommended_experiments.length}} experiments proposed</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Verifiable execution supply chain</h3><p class="mt-1 text-[10px] text-gray-500">Attest the governing proof, release state, compiled policy, canonical routes, and secret-free material manifest.</p><button class="mt-3 rounded bg-gray-900 px-3 py-2 text-xs text-white" @click="act('supply_chain_attestation')">Attest latest execution chain</button><p v-if="state.assurance.attestations[0]" class="mt-2 text-[10px]" :class="state.assurance.attestations[0].status==='verified'?'text-emerald-700':'text-amber-700'">Latest: {{state.assurance.attestations[0].status}} · {{state.assurance.attestations[0].attestation_digest.slice(0,14)}}…</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Living consent and delegation graph</h3><div class="mt-2 grid grid-cols-2 gap-2"><input v-model="delegation.delegate_subject" class="col-span-2 rounded border p-2 text-xs"><input v-model="delegation.scopes" class="rounded border p-2 text-xs"><input v-model.number="delegation.minutes" type="number" min="1" max="1440" class="rounded border p-2 text-xs"><input v-model="delegation.purpose" class="col-span-2 rounded border p-2 text-xs"></div><button class="mt-2 rounded bg-gray-900 px-3 py-2 text-xs text-white" @click="delegate">Delegate attenuated authority</button><p class="mt-2 text-[10px] text-gray-500">No scope amplification, expiry extension, or unbounded redelegation.</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Outcome-backed capability market</h3><div class="mt-2 grid grid-cols-2 gap-2"><input v-model="market.capability" class="col-span-2 rounded border p-2 text-xs"><input v-model="market.provider_subject" class="col-span-2 rounded border p-2 text-xs"><input v-model="market.metric" class="rounded border p-2 text-xs"><input v-model.number="market.target" type="number" step=".01" class="rounded border p-2 text-xs"></div><button class="mt-2 rounded bg-gray-900 px-3 py-2 text-xs text-white" @click="act('outcome_market_contract',market)">Propose verified-outcome contract</button><p class="mt-2 text-[10px] text-gray-500">No automatic payment; activation and settlement require independent verification and approval.</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Organizational memory compiler</h3><p class="mt-1 text-[10px] text-gray-500">Compile decisions, incidents, policies, causal evidence, and intent into reviewable guidance for training and just-in-time decisions.</p><button class="mt-3 rounded bg-gray-900 px-3 py-2 text-xs text-white" @click="act('compile_memory')">Compile operating memory</button><p v-if="state.assurance.memories[0]" class="mt-2 text-[10px] text-amber-700">Latest: {{state.assurance.memories[0].status}} · human review required</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Anticipatory inclusion engine</h3><textarea v-model="inclusion" rows="3" class="mt-2 w-full rounded border p-2 text-xs"/><button class="mt-2 rounded bg-gray-900 px-3 py-2 text-xs text-white" @click="act('inclusion_assessment',{proposed_change:inclusion})">Predict inclusion barriers</button><p v-if="state.assurance.inclusion[0]" class="mt-2 text-[10px] text-amber-700">Latest: {{state.assurance.inclusion[0].overall_risk}} risk · {{state.assurance.inclusion[0].decision}} · {{state.assurance.inclusion[0].predicted_barriers.length}} barriers</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Constitutional red-team court</h3><textarea v-model="proposition" rows="3" class="mt-2 w-full rounded border p-2 text-xs"/><button class="mt-2 rounded bg-rose-800 px-3 py-2 text-xs text-white" @click="act('red_team_court',{proposition})">Convene adversarial court</button><p v-if="state.assurance.redTeams[0]" class="mt-2 text-[10px] text-rose-700">Latest verdict: {{state.assurance.redTeams[0].verdict}} · appeal preserved</p></article></div><p v-if="message" role="status" class="mt-3 rounded bg-sky-50 p-2 text-xs text-sky-800">{{message}}</p></section></template>
